requests.testScript:
export {};
const jsonData = pw.response.body; 
pw.env.set("ACCESS_TOKEN", "Bearer " + jsonData.data.accessToken);
pw.env.set("REFRESH_TOKEN", "Bearer "+ jsonData.data.refreshToken);

pw.test("Status code is 200", ()=> {
    pw.expect(pw.response.status).toBe(200);
});

